import request from '@/utils/request'
import { SMS_SCENE } from '@/store'

export const auth = {
  // 密码登录
  loginWithPassword: async (data) => {
    const response = await request.post('/api/v1/users/auth/login/password/', data)
    return response
  },

  // 退出登录
  logout: async () => {
    const refreshToken = localStorage.getItem('refresh_token')
    if (!refreshToken) return

    return request.post('/api/v1/users/auth/logout/', { refresh: refreshToken })
  },

  // 刷新 token
  refreshToken: (data) => {
    return request.post('/api/v1/users/auth/token/refresh/', data)
  },

  // 注册
  register: (data) => {
    return request.post('/api/v1/users/auth/register/', {
      phone: data.phone,
      code: data.code,
      password: data.password,
      confirm_password: data.confirm_password
    })
  },

  // 重置密码
  resetPassword: (data) => {
    return request.post('/api/v1/users/auth/password/reset/', {
      phone: data.phone,
      code: data.code,
      new_password: data.password,
      confirm_password: data.confirmPassword
    })
  }
}
